55	const PROCESSING_FEE = 5;
56	
57	const BASE_PREMIUM: Record<string, number> = {
58	  sword: 100,
59	  amulet: 60,
60	  staff: 80,
61	  potion: 40,
62	  rune: 25,
63	  moonstone: 25,
64	};
65	
66	const CURSED_SURCHARGE_RATE = 0.5;
67	const HIGH_ENCHANTMENT_THRESHOLD = 5;
68	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
69	const FIRST_INSURANCE_RATE = 0.1;
70	const LOYALTY_THRESHOLD_YEARS = 2;
71	const LOYALTY_DISCOUNT_RATE = 0.2;
72	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
73	
74	const isCursed = (item: Item): boolean => item.cursed === true;
75	const isHighlyEnchanted = (item: Item): boolean =>
76	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
77	
78	const surchargeRate = (item: Item): number =>
79	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
80	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
81	
82	const itemBaseValue = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
83	
84	const itemSurcharge = (item: Item): number =>
85	  itemBaseValue(item) * surchargeRate(item);
86	
87	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
88	const BLOCK_SIZE = 3;
89	const BLOCK_PREMIUM = 60;
90	
91	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
92	
93	const sumBy = <T>(values: T[], measure: (value: T) => number): number =>
94	  values.reduce((sum, value) => sum + measure(value), 0);
95	
96	const groupByType = (items: Item[]): Item[][] => {
97	  const byType = new Map<string, Item[]>();
98	  for (const item of items) {
99	    const group = byType.get(item.type) ?? [];
100	    group.push(item);
101	    byType.set(item.type, group);
102	  }
103	  return [...byType.values()];
104	};
105	
106	const groupPremium = (group: Item[]): number =>
107	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBy(group, itemBaseValue);
108	
109	const componentsPremium = (components: Item[]): number =>
110	  sumBy(groupByType(components), groupPremium);
111	
112	const policyBasePremium = (items: Item[]): number =>
113	  componentsPremium(items.filter(isComponent)) +
114	  sumBy(items.filter((item) => !isComponent(item)), itemBaseValue);
115	
116	const totalSurcharges = (items: Item[]): number => sumBy(items, itemSurcharge);
117	
118	const loyaltyRate = (customer: Customer): number =>
119	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0;
120	
121	const followUpRate = (isFollowUp: boolean): number =>
122	  isFollowUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
123	
124	const netPolicyRate = (customer: Customer, isFollowUp: boolean): number =>
125	  FIRST_INSURANCE_RATE - loyaltyRate(customer) - followUpRate(isFollowUp);
126	
127	const quotePremium = (customer: Customer, items: Item[], isFollowUp: boolean): number => {
128	  const base = policyBasePremium(items);
129	  const surcharges = totalSurcharges(items);
130	  const policyAdjustment = base * netPolicyRate(customer, isFollowUp);
131	  return Math.ceil(base + surcharges + policyAdjustment + PROCESSING_FEE);
132	};
133	
134	export const runScenario = (scenario: Scenario): ScenarioResult => {
135	  let quoteCount = 0;
136	  const results = scenario.steps.map((step): StepResult => {
137	    if (step.op === "quote") {
138	      const isFollowUp = quoteCount > 0;
139	      quoteCount += 1;
140	      return { premium: quotePremium(scenario.customer, step.items, isFollowUp) };
141	    }
142	    return { payout: 0, remainingCap: 0 };
143	  });
144	  return { results };
145	};
